#!/usr/bin/env node
// Bundle concepts/*.json + capstones.json into a single loadable .js file.
//
// Why: modern browsers block fetch() of local JSON files when the host page
// is opened via file:// (no server). The notebook's README explicitly says
// double-clicking index.html should work, so pathway.html can't rely on
// fetch. A <script src="./concepts/bundle.js"> tag works from file:// and
// exposes the same data as a window global.
//
// Usage:  node scripts/build-concepts-bundle.mjs
// Output: concepts/bundle.js (overwritten)
//
// Run this whenever a concepts/*.json or capstones.json changes.

import { readFileSync, readdirSync, writeFileSync } from 'node:fs';
import { dirname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const repoRoot = resolve(dirname(__filename), '..');
const conceptsDir = join(repoRoot, 'concepts');
const outPath = join(conceptsDir, 'bundle.js');

const indexRaw = readFileSync(join(conceptsDir, 'index.json'), 'utf8');
const index = JSON.parse(indexRaw);

const topics = {};
for (const t of index.topics) {
  const p = join(conceptsDir, `${t}.json`);
  topics[t] = JSON.parse(readFileSync(p, 'utf8'));
}

const capstones = JSON.parse(readFileSync(join(conceptsDir, 'capstones.json'), 'utf8'));
const sections = JSON.parse(readFileSync(join(conceptsDir, 'sections.json'), 'utf8'));

const payload = { index, topics, capstones, sections };
const body = JSON.stringify(payload, null, 2);

const js =
`// Auto-generated by scripts/build-concepts-bundle.mjs — DO NOT EDIT.
// Regenerate with:  node scripts/build-concepts-bundle.mjs
// Source of truth: concepts/index.json + each registered topic + capstones.json + sections.json.
window.__MVConcepts = ${body};
`;

writeFileSync(outPath, js);

const topicCount = Object.keys(topics).length;
const conceptCount = Object.values(topics).reduce(
  (n, t) => n + (t.concepts?.length || 0), 0);
console.log(`wrote ${outPath} — ${topicCount} topics, ${conceptCount} concepts, ${capstones.capstones.length} capstones`);
